import{_ as n,C as i,o as t,c as r,a2 as o,b as l,w as a,a as h,E as d,a3 as c}from"./chunks/framework.B72_uj9U.js";const y=JSON.parse('{"title":"Pi — The Minimal Agent Loop","description":"","frontmatter":{},"headers":[],"relativePath":"research/agents/pi-coding-agent/agentic-loop.md","filePath":"research/agents/pi-coding-agent/agentic-loop.md"}'),p={name:"research/agents/pi-coding-agent/agentic-loop.md"};function g(u,e,m,b,f,x){const s=i("Mermaid");return t(),r("div",null,[e[1]||(e[1]=o('<h1 id="pi-—-the-minimal-agent-loop" tabindex="-1">Pi — The Minimal Agent Loop <a class="header-anchor" href="#pi-—-the-minimal-agent-loop" aria-label="Permalink to &quot;Pi — The Minimal Agent Loop&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Pi&#39;s agentic loop is deliberately simple. Where other coding agents (Claude Code, Aider, Goose) build complex multi-phase loops with planning, validation, lint-test-fix cycles, and sub-agent delegation, Pi implements a straightforward message → LLM → tool calls → results cycle. Complexity is pushed to extensions rather than baked into the core loop.</p><p>This simplicity is a conscious design choice. Mario Zechner&#39;s philosophy is that a complex core loop means complex debugging, unpredictable behavior, and prompt cache instability. By keeping the loop minimal, Pi ensures that the agent&#39;s behavior is transparent and that extensions can modify it at well-defined points.</p><h2 id="the-core-loop" tabindex="-1">The Core Loop <a class="header-anchor" href="#the-core-loop" aria-label="Permalink to &quot;The Core Loop&quot;">​</a></h2>',5)),(t(),l(c,null,{default:a(()=>[d(s,{id:"mermaid-15",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20A%5B%22User%20Input%3Cbr%2F%3E(Interactive%20%2F%20RPC%20%2F%20SDK%20%2F%20Print)%22%5D%20--%3E%20B%5B%22Message%20Assembly%3Cbr%2F%3ECheck%20message%20queue%20for%20steering%20messages%2C%3Cbr%2F%3Eappend%20to%20conversation%22%5D%0A%20%20%20%20B%20--%3E%20C%5B%22LLM%20Call%20(streaming)%3Cbr%2F%3ESend%20conversation%20to%20provider%20via%20pi-ai%3Cbr%2F%3EStream%20tokens%20to%20TUI%20as%20they%20arrive%22%5D%0A%20%20%20%20C%20--%20%22No%20tool%20calls%22%20--%3E%20D%5B%22Done%3Cbr%2F%3E(wait%20for%20input)%22%5D%0A%20%20%20%20C%20--%20%22Tool%20calls%22%20--%3E%20E%5B%22Tool%20Calls%20(sequential)%3Cbr%2F%3EExecute%20read%2Fwrite%2Fedit%2Fbash%3Cbr%2F%3Eor%20extension-registered%20tools%22%5D%0A%20%20%20%20E%20--%3E%20F%5B%22Tool%20Results%3Cbr%2F%3EAppend%20results%20to%20conversation%22%5D%0A%20%20%20%20F%20--%3E%20G%5B%22Context%20Check%3Cbr%2F%3ECheck%20token%20count%3B%20trigger%20compaction%3Cbr%2F%3Eif%20approaching%20limit%22%5D%0A%20%20%20%20G%20--%3E%20C%0A"})]),fallback:a(()=>[...e[0]||(e[0]=[h(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=o(`<h3 id="phase-1-message-assembly" tabindex="-1">Phase 1: Message Assembly <a class="header-anchor" href="#phase-1-message-assembly" aria-label="Permalink to &quot;Phase 1: Message Assembly&quot;">​</a></h3><p>The loop begins with a user message arriving through one of the four modes (Interactive, Print/JSON, RPC, SDK). Before sending to the LLM, Pi checks the <strong>message queue</strong> for any pending steering messages that should be injected.</p><p>Context is assembled from:</p><ul><li>The conversation history (stored in the tree-structured JSONL session)</li><li>System prompt (default + SYSTEM.md overrides)</li><li>AGENTS.md project instructions</li><li>Any dynamically injected context from extensions</li></ul><h3 id="phase-2-llm-call" tabindex="-1">Phase 2: LLM Call <a class="header-anchor" href="#phase-2-llm-call" aria-label="Permalink to &quot;Phase 2: LLM Call&quot;">​</a></h3><p>Pi sends the assembled conversation to the configured provider via <code>pi-ai</code>. The response streams token-by-token, rendered to the TUI in real-time via differential rendering. During streaming, the user can:</p><ul><li>Press Enter to submit a <strong>steering message</strong> (delivered after current tool call)</li><li>Press Alt+Enter to queue a <strong>follow-up</strong> (waits until agent finishes)</li></ul><h3 id="phase-3-tool-execution" tabindex="-1">Phase 3: Tool Execution <a class="header-anchor" href="#phase-3-tool-execution" aria-label="Permalink to &quot;Phase 3: Tool Execution&quot;">​</a></h3><p>If the LLM response includes tool calls, Pi executes them against the registered tool handlers. The default tools are <code>read</code>, <code>write</code>, <code>edit</code>, and <code>bash</code>, but extensions can register additional tools or replace the defaults entirely.</p><p>Tool calls are executed and their results are appended to the conversation history.</p><h3 id="phase-4-context-check-compaction" tabindex="-1">Phase 4: Context Check &amp; Compaction <a class="header-anchor" href="#phase-4-context-check-compaction" aria-label="Permalink to &quot;Phase 4: Context Check &amp; Compaction&quot;">​</a></h3><p>After tool results are appended, Pi checks whether the conversation is approaching the model&#39;s context window limit. If it is, <strong>compaction</strong> is triggered — older messages are summarized to free space while preserving essential context (see <a href="./context-management.html">context-management.md</a>).</p><h3 id="phase-5-loop-or-stop" tabindex="-1">Phase 5: Loop or Stop <a class="header-anchor" href="#phase-5-loop-or-stop" aria-label="Permalink to &quot;Phase 5: Loop or Stop&quot;">​</a></h3><p>If the LLM made tool calls, the loop continues back to Phase 2 with the updated conversation. If the LLM responded with just text (no tool calls), the loop pauses and waits for the next user input.</p><h2 id="the-message-queue" tabindex="-1">The Message Queue <a class="header-anchor" href="#the-message-queue" aria-label="Permalink to &quot;The Message Queue&quot;">​</a></h2><p>Pi&#39;s message queue is one of its more interesting interaction patterns. While the agent is working (executing tool calls, waiting for LLM responses), the user can submit messages that are queued for delivery at specific points.</p><h3 id="steering-messages-enter" tabindex="-1">Steering Messages (Enter) <a class="header-anchor" href="#steering-messages-enter" aria-label="Permalink to &quot;Steering Messages (Enter)&quot;">​</a></h3><p>Pressing Enter while the agent works submits a <strong>steering message</strong>. This message is delivered to the LLM after the current tool call completes but before the next LLM inference. This allows the user to redirect the agent mid-task:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Agent is running bash tests...</span></span>
<span class="line"><span>User presses Enter: &quot;Actually, skip the integration tests, just fix the unit tests&quot;</span></span>
<span class="line"><span>→ Message delivered after bash completes</span></span>
<span class="line"><span>→ LLM sees the steering message in its next inference</span></span>
<span class="line"><span>→ Agent adjusts course</span></span></code></pre></div><p><strong>Delivery timing</strong>: After the current tool call finishes, before the next LLM call.</p><h3 id="follow-up-messages-alt-enter" tabindex="-1">Follow-up Messages (Alt+Enter) <a class="header-anchor" href="#follow-up-messages-alt-enter" aria-label="Permalink to &quot;Follow-up Messages (Alt+Enter)&quot;">​</a></h3><p>Pressing Alt+Enter queues a <strong>follow-up message</strong>. This waits until the agent completely finishes its current task (all tool calls done, final text response given) before being delivered:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Agent is working on feature A...</span></span>
<span class="line"><span>User presses Alt+Enter: &quot;After you&#39;re done, also update the README&quot;</span></span>
<span class="line"><span>→ Message waits until agent finishes feature A</span></span>
<span class="line"><span>→ Delivered as a new user message</span></span>
<span class="line"><span>→ Agent starts working on README</span></span></code></pre></div><p><strong>Delivery timing</strong>: After the agent&#39;s complete turn (text response with no tool calls).</p><h3 id="configurable-delivery-modes" tabindex="-1">Configurable Delivery Modes <a class="header-anchor" href="#configurable-delivery-modes" aria-label="Permalink to &quot;Configurable Delivery Modes&quot;">​</a></h3><p>Extensions can customize message queue behavior — changing delivery timing, adding message types, or implementing priority queues. This flexibility means the message queue can be adapted to different workflows without modifying the core loop.</p><h2 id="how-the-loop-stays-simple" tabindex="-1">How the Loop Stays Simple <a class="header-anchor" href="#how-the-loop-stays-simple" aria-label="Permalink to &quot;How the Loop Stays Simple&quot;">​</a></h2><p>The key insight is what the loop does NOT do:</p><table tabindex="0"><thead><tr><th>Feature</th><th>Other Agents</th><th>Pi</th></tr></thead><tbody><tr><td>Plan-then-execute</td><td>Built into loop</td><td>Extension or file-based</td></tr><tr><td>Lint-test-fix cycle</td><td>Automatic retry</td><td>Extension or manual</td></tr><tr><td>Sub-agent delegation</td><td>Built-in orchestration</td><td>Spawn via tmux or extension</td></tr><tr><td>Permission gates</td><td>Interrupt loop for approval</td><td>Extension or container isolation</td></tr><tr><td>Background tasks</td><td>Built-in task management</td><td>Use tmux</td></tr><tr><td>Automatic retries</td><td>Retry logic in loop</td><td>Extension</td></tr></tbody></table><p>Each of these features can be added via extensions, but none of them complicate the core loop. This means:</p><ol><li><strong>Debugging is straightforward</strong> — the loop has one path, not branching logic</li><li><strong>Prompt cache stays stable</strong> — no conditional system prompt sections</li><li><strong>Behavior is predictable</strong> — no hidden retry logic or automatic fixes</li><li><strong>Extensions have clear hooks</strong> — they modify behavior at well-defined points</li></ol><h2 id="compaction-triggering" tabindex="-1">Compaction Triggering <a class="header-anchor" href="#compaction-triggering" aria-label="Permalink to &quot;Compaction Triggering&quot;">​</a></h2><p>Compaction is the only &quot;complex&quot; behavior in the core loop. When the conversation approaches the context window limit:</p><ol><li>Pi detects the token count is above a configurable threshold</li><li>Older messages (not the most recent exchanges) are summarized</li><li>The summary replaces the original messages in the conversation</li><li>The loop continues with the compacted context</li></ol><p>Extensions can fully customize compaction behavior — changing the summarization prompt, the threshold, which messages are compacted, or replacing the entire compaction strategy.</p><h2 id="event-system" tabindex="-1">Event System <a class="header-anchor" href="#event-system" aria-label="Permalink to &quot;Event System&quot;">​</a></h2><p>Throughout the loop, Pi emits events that extensions can subscribe to:</p><ul><li><code>message:received</code> — User message arrived</li><li><code>message:streaming</code> — LLM tokens arriving</li><li><code>tool:start</code> — Tool call about to execute</li><li><code>tool:complete</code> — Tool call finished with result</li><li><code>response:complete</code> — LLM turn finished</li><li><code>compaction:triggered</code> — Context compaction starting</li><li><code>session:updated</code> — Session state changed</li></ul><p>This event-driven architecture lets extensions observe and modify loop behavior without touching the loop itself. An extension could log all tool calls, gate certain operations behind approval prompts, implement automatic rollback on errors, or inject additional context between turns — all through event handlers.</p><h2 id="comparison-to-other-agent-loops" tabindex="-1">Comparison to Other Agent Loops <a class="header-anchor" href="#comparison-to-other-agent-loops" aria-label="Permalink to &quot;Comparison to Other Agent Loops&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Agent</th><th>Loop Complexity</th><th>Built-in Phases</th></tr></thead><tbody><tr><td>Aider</td><td>Medium</td><td>Edit → Apply → Lint → Test → Fix</td></tr><tr><td>Claude Code</td><td>High</td><td>Plan → Execute → Validate → Sub-agents</td></tr><tr><td>Goose</td><td>Medium</td><td>Think → Act → Observe + Extensions</td></tr><tr><td><strong>Pi</strong></td><td><strong>Low</strong></td><td><strong>Message → LLM → Tools → Loop</strong></td></tr></tbody></table><p>Pi&#39;s loop is the simplest of the major terminal coding agents. This is not a limitation — it&#39;s the core architectural decision that enables everything else. The loop provides a stable foundation; extensions provide the features.</p>`,42))])}const P=n(p,[["render",g]]);export{y as __pageData,P as default};
